TAny = TypeVar("TAny")
TModel = TypeVar("TModel", bound=AnyBaseModel)


def create_pydantic_model(model_cls: type[TModel], /, **kwargs: Any) -> TModel:
    if is_pydantic_v2_model(model_cls):
        return model_cls.model_validate(kwargs, from_attributes=True)  # type: ignore[ty:invalid-return-type]

    return model_cls(**kwargs)


@singledispatch
def get_model_fields(model: type[AnyBaseModel], /) -> dict[str, AnyField]:
    if is_pydantic_v2_model(model):
        return cast(dict[str, AnyField], copy(model.model_fields))

    return cast(dict[str, AnyField], copy(model.__fields__))


def is_pydantic_field(field: Any, /) -> bool:
    return is_pydantic_v2_field(field) or is_pydantic_v1_field(field)


def is_pydantic_v2_field(field: Any, /) -> bool:
    return isinstance(field, FieldV2)


def is_pydantic_v1_field(field: Any, /) -> bool:
    cls = type(field)

    names = {"pydantic.v1.fields.ModelField"}
    if not IS_PYDANTIC_V2:
        names.add("pydantic.fields.ModelField")

    return any(f"{mro_cls.__module__}.{mro_cls.__qualname__}" in names for mro_cls in inspect.getmro(cls))


@singledispatch
def make_field_optional(field: Any) -> Any:  # pragma: no cover
    return None


@make_field_optional.register
def _(field: FieldV2, /) -> Any:
    field = copy(field)

    field.annotation = field.annotation | None  # type: ignore[ty:unsupported-operator]
    field.default = None
    field.default_factory = None

    return field


@singledispatch
def make_field_required(field: Any, /) -> Any:  # pragma: no cover
    field = copy(field)
    field.required = True
    field.default = ...
    field.default_factory = None

    return field

from __future__ import annotations

import math
import uuid
from typing import Any, ClassVar, Generic, TypeVar

T = TypeVar("T")


class Convertor(Generic[T]):
    regex: ClassVar[str] = ""

    def convert(self, value: str) -> T:
        raise NotImplementedError()  # pragma: no cover

    def to_string(self, value: T) -> str:
        raise NotImplementedError()  # pragma: no cover


class StringConvertor(Convertor[str]):
    regex = "[^/]+"

    def convert(self, value: str) -> str:
        return value

    def to_string(self, value: str) -> str:
        value = str(value)
        assert "/" not in value, "May not contain path separators"
        assert value, "Must not be empty"
        return value


class PathConvertor(Convertor[str]):
    regex = ".*"

    def convert(self, value: str) -> str:
        return str(value)

    def to_string(self, value: str) -> str:
        return str(value)


class IntegerConvertor(Convertor[int]):
    regex = "[0-9]+"

    def convert(self, value: str) -> int:
        return int(value)

    def to_string(self, value: int) -> str:
        value = int(value)
        assert value >= 0, "Negative integers are not supported"
        return str(value)


class FloatConvertor(Convertor[float]):
    regex = r"[0-9]+(\.[0-9]+)?"

    def convert(self, value: str) -> float:
        return float(value)

    def to_string(self, value: float) -> str:
        value = float(value)
        assert value >= 0.0, "Negative floats are not supported"
        assert not math.isnan(value), "NaN values are not supported"
        assert not math.isinf(value), "Infinite values are not supported"
        return ("%0.20f" % value).rstrip("0").rstrip(".")


class UUIDConvertor(Convertor[uuid.UUID]):
    regex = "[0-9a-fA-F]{8}-?[0-9a-fA-F]{4}-?[0-9a-fA-F]{4}-?[0-9a-fA-F]{4}-?[0-9a-fA-F]{12}"

    def convert(self, value: str) -> uuid.UUID:
        return uuid.UUID(value)

    def to_string(self, value: uuid.UUID) -> str:
        return str(value)


CONVERTOR_TYPES: dict[str, Convertor[Any]] = {
    "str": StringConvertor(),
    "path": PathConvertor(),
    "int": IntegerConvertor(),
    "float": FloatConvertor(),
    "uuid": UUIDConvertor(),
}


def register_url_convertor(key: str, convertor: Convertor[Any]) -> None:
    CONVERTOR_TYPES[key] = convertor

